def maxLengthBetweenEqualCharacters(s: str) -> int:
    count_dict = {}
    max_length = -1
    for char in s:
        if char in count_dict:
            count_dict[char] += 1
        else:
            count_dict[char] = 1
        if count_dict[char] % 2 == 0:
            max_length = max(max_length, count_dict[char])
            del count_dict[char]
    return max_length

